namespace ViewsTests;

public class OptionSelectorAutoWidthTests
{
    // Claude - Opus 4.5
    [Fact]
    public void AutoWidth_ShouldRecalculate_WhenLabelsSetAfterConstruction_Horizontal ()
    {
        // Arrange
        OptionSelector selector = new ()
        {
            Orientation = Orientation.Horizontal,
        };

        // Act - set labels after construction (the bug scenario)
        selector.Labels = ["IMDb (Recommended)", "TMDb"];
        selector.Values = [0, 1];

        // Simulate what the layout engine would do
        // The selector's Width is Dim.Auto(DimAutoStyle.Content), so it should calculate
        // based on the content of its subviews.
        selector.Layout ();

        // Assert - both checkboxes should be fully visible
        CheckBox[] checkBoxes = selector.SubViews.OfType<CheckBox> ().ToArray ();
        Assert.Equal (2, checkBoxes.Length);

        // The checkboxes' widths should be large enough to contain their labels
        foreach (CheckBox cb in checkBoxes)
        {
            // Frame width should be >= the title text width
            Assert.True (cb.Frame.Width >= cb.Title.GetColumns (),
                         $"CheckBox '{cb.Title}' width ({cb.Frame.Width}) should be >= text width ({cb.Title.GetColumns ()})");
        }

        // The selector's total width should be at least the sum of both checkbox widths + horizontal spacing
        int totalCheckBoxWidth = checkBoxes.Sum (cb => cb.Frame.Width);
        int horizontalSpace = selector.HorizontalSpace;
        int expectedMinWidth = totalCheckBoxWidth + horizontalSpace; // space between 2 items = 1 gap
        Assert.True (selector.Frame.Width >= expectedMinWidth,
                     $"Selector width ({selector.Frame.Width}) should be >= sum of checkbox widths ({totalCheckBoxWidth}) + horizontal space ({horizontalSpace}) = {expectedMinWidth}");
    }
}

