protected void SetLayout ()
{
    var maxNaturalCheckBoxWidth = 0;

    if (Values?.Count > 0)
    {
        if (Orientation == Orientation.Vertical)
        {
            maxNaturalCheckBoxWidth = SubViews.OfType<CheckBox> ()
                                              .Max (v =>
                                                    {
                                                        v.SetRelativeLayout (App?.Screen.Size ?? new Size (2048, 2048));

