        }
        else
        {
            // Precompute natural widths for horizontal so that sequential positions
            // don't depend on the SuperView content size (which depends on our own DimAuto.Content width).
            // Without this, Pos.Align creates a circular dependency that prevents DimAuto.Content
            // from recalculating when Labels/Values are set after construction.
