        var maxNaturalCheckBoxWidth = 0;

        if (Values?.Count > 0)
        {
            if (Orientation == Orientation.Vertical)
            {
                maxNaturalCheckBoxWidth = SubViews.OfType<CheckBox> ()
                                                  .Max (v =>
                                                        {
                                                            v.SetRelativeLayout (App?.Screen.Size ?? new Size (2048, 2048));

                                                            return v.Frame.Width;
                                                        });
            }
            else
            {
                // Precompute natural widths for horizontal so that sequential positions
                // don't depend on the SuperView content size (which depends on our own DimAuto.Content width).
                // Without this, Pos.Align creates a circular dependency that prevents DimAuto.Content
                // from recalculating when Labels/Values are set after construction.
                foreach (CheckBox cb in SubViews.OfType<CheckBox> ())
                {
                    cb.SetRelativeLayout (App?.Screen.Size ?? new Size (2048, 2048));
                }
            }
        }

        int xOffset = 0;

        for (var i = 0; i < SubViews.Count; i++)
        {
            if (Orientation == Orientation.Vertical)
            {
                SubViews.ElementAt (i).X = 0;
                SubViews.ElementAt (i).Y = Pos.Align (Alignment.Start, AlignmentModes.StartToEnd);
                SubViews.ElementAt (i).Margin.Thickness = new Thickness (0);
                SubViews.ElementAt (i).Width = Dim.Func (_ => maxNaturalCheckBoxWidth);
            }
            else
            {
                // Use absolute X position based on pre-computed widths to avoid circular
                // dependency with DimAuto.Content layout calculation
                SubViews.ElementAt (i).X = xOffset;
                xOffset += SubViews.ElementAt (i).Frame.Width + (i < SubViews.Count - 1 ? _horizontalSpace : 0);
                SubViews.ElementAt (i).Y = 0;
                SubViews.ElementAt (i).Margin.Thickness = new Thickness (0, 0, i < SubViews.Count - 1 ? _horizontalSpace : 0, 0);
                SubViews.ElementAt (i).Width = Dim.Auto ();
            }
        }
    }

