// TODO: PosAlign.CalculateMinDimension is a hack. Need to figure out a better way of doing this.
    /// <summary>
    ///     Returns the minimum size a group of views with the same <paramref name="groupId"/> can be.
    /// </summary>
    /// <param name="groupId"></param>
    /// <param name="views"></param>
    /// <param name="dimension"></param>
    /// <returns></returns>
    public static int CalculateMinDimension (int groupId, IReadOnlyCollection<View> views, Dimension dimension)
    {
        var dimensionsSum = 0;

        // 2048 x 2048 supports unit testing where no App is running.
        Size screenSize = views.FirstOrDefault ()?.App?.Screen.Size ?? new Size (2048, 2048);

        foreach (View view in views)
        {
            if (!HasGroupId (view, dimension, groupId))
            {
                continue;
            }

            PosAlign? posAlign = dimension == Dimension.Width ? view.X as PosAlign : view.Y as PosAlign;

            if (posAlign is { })
            {
                // Use Dim.Calculate to get the view's intrinsic dimension
                // rather than relying on Frame.Width/Height which may be 0
                // if the view hasn't been laid out yet (e.g., when DimAuto.Content
                // is being calculated for a SuperView that contains PosAlign subviews).
                Dim dim = dimension == Dimension.Width ? view.Width : view.Height;

                int viewSize = dim.Calculate (0, dimension == Dimension.Width ? screenSize.Width * 4 : screenSize.Height * 4, view, dimension);

                dimensionsSum += viewSize;
            }
        }

        // Align
        return dimensionsSum;
    }

